  input clock,
        reset
);

  wire full = 1'h0;
  wire full_0 = full;
endmodule

module Baz(
  input clock,
        reset
);

  wire full = 1'h0;
  wire full_0 = full;
endmodule

module Qux(
  input clock,
        reset
);

endmodule

module Foo(
  input clock,
        reset
);

  Bar bar (
    .clock (clock),
    .reset (reset)
  );
  Baz baz (
    .clock (clock),
    .reset (reset)
  );
  Qux qux (
    .clock (clock),
    .reset (reset)
